#!/usr/bin/env bash
# gp.sh — 一个 GP / 投资人的一周(三尺度之「周」) SOP walkthrough for 风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金)"
WORKFLOW="一个 GP / 投资人的一周(三尺度之「周」)"

usage() {
  cat <<EOF
gp.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./gp.sh             # interactive
  ./gp.sh --dry-run
  ./gp.sh --json
  ./gp.sh --explain
  ./gp.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "一个 GP / 投资人的一周(三尺度之「周」)" 工作流。

一句话: 把一个早期 VC 的一周从「无序救火」变成「有节奏的并行流水线」—— deal review / pitch 会 / partner meeting / board meeting / LP & founder 触达 五条线同时滚动。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • Power-law 是世界观，不是事后观察到的结果 — 错过比投错致命: VC 的整门生意建立在「一支基金 80%+（业内估计，幂律分布的概数）回报来自 1-2 个 outlier、其余多数 deal 回本或归零」之上；因此判断一个 deal 的第一性问题不是「它稳不稳 /
  • 市场 / 赛道决定论 — 但「市场 vs 团队谁第一」是本行未决的派系张力: 这一行有一条强力镜片——「好团队遇上烂市场，市场赢；烂团队遇上好市场，市场赢」，市场天花板能不能容下一个 return-the-fund 的 outlier 是早期判断的硬约束；但与之并存的是另一极—

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**周一 partner meeting / deal review 准备**:把上周 sourced 的 deal 整理进 CRM(Affinity),给每个 deal 标阶段 + 一句话推荐/否决意见,准备本周要 present 的 1-2 个 deal。"
  "**partner meeting 本身**:全 partnership 过一遍 active pipeline,对在谈 deal 做 go / no-go / 继续尽调 的集体判断,分配本周尽调任务。"
  "**本周 pitch 会(first meetings)**:见 3-8 个新公司,每个 30-60 分钟,会后当天写下 gut read + next step(pass / 二次会 / 进尽调)。"
  "**进行中 deal 的尽调动作**:对已进尽调的 deal 推进当周该做的一步(reference call / 产品试用 / 算 unit economics / 查 cap table)。"
  "**portfolio / board / LP 触达**:本周该开的 board meeting 开掉,portfolio 公司的求助回掉,有 LP call 的接掉。"
)
declare -a FAILURE_MODES=(
  "**sourcing 漏斗断供**:某周忙投后 / 募资就完全不见新公司 —— 「Block 固定的 first-meeting 时段(如每周二、周四下午),哪怕只见 2 家也别归零;deal flow 是流量不是库存」。"
  "**partner meeting 变成念清单**:全员逐个 deal 过一遍、无人异步准备 —— 「会前异步更新 CRM,会上只讨论有真实分歧的 deal,把 3 小时会压到 1 小时」。"
  "**投后失明**:只顾看新 deal,portfolio 公司的现金跑道 / 关键人离职信号被漏看 —— 「每周固定 triage 一遍 portfolio 的 default-alive 状态,把要救的公司提前一个月发现,而不是等 founder 来报丧」。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "gp-walkthrough"
fi
